  ('social-worker-moex-01071', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作價值與倫理發展的敘述，下列何者正確？①19世紀末期，社會工作專業開始發展階', '["20世紀睦鄰運動的興 起，社會工作者轉而偏重關注社會改革議題，而非案主的道德觀", "1960年代，社會工作者關注 焦點轉向社會正義、權利與改革", "1970年代，應用性的專業倫理興起", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
