  ('social-worker-moex-01076', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '按照Reamer（1995）對於業務過失（malpractice）的定義，一間職能復健機構的社會工作師未經 機構的案主們同意，就挪用案主的工作復健基金作為營養午餐費用，這是屬於何種業務過失？', '["瀆職", "濫權", "侵權", "怠職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
